import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner();
        StringBuilder sb = new StringBuilder();
        int T = fs.nextInt();
        if (T == Integer.MIN_VALUE) return; // no input
        while (T-- > 0) {
            int N = fs.nextInt();
            if (N == Integer.MIN_VALUE) break; // malformed input
            int[][] a = new int[N + 1][N + 1]; // 1‑based indexing
            for (int i = 1; i <= N; i++) {
                for (int j = 1; j <= N; j++) {
                    a[i][j] = fs.nextInt();
                }
            }
            // pref[v][i][j] = number of occurrences of value v in rectangle (1,1) .. (i,j)
            int[][][] pref = new int[11][N + 1][N + 1];
            for (int v = 1; v <= 10; v++) {
                for (int i = 1; i <= N; i++) {
                    int rowSum = 0;
                    for (int j = 1; j <= N; j++) {
                        rowSum += (a[i][j] == v) ? 1 : 0;
                        pref[v][i][j] = pref[v][i - 1][j] + rowSum;
                    }
                }
            }
            int Q = fs.nextInt();
            if (Q == Integer.MIN_VALUE) break; // malformed input
            while (Q-- > 0) {
                int x1 = fs.nextInt();
                int y1 = fs.nextInt();
                int x2 = fs.nextInt();
                int y2 = fs.nextInt();
                // Validate coordinates to avoid out‑of‑bounds access
                if (x1 < 1) x1 = 1;
                if (y1 < 1) y1 = 1;
                if (x2 > N) x2 = N;
                if (y2 > N) y2 = N;
                if (x1 > x2 || y1 > y2) {
                    sb.append(0).append('\n');
                    continue;
                }
                int distinct = 0;
                for (int v = 1; v <= 10; v++) {
                    int cnt = pref[v][x2][y2] - pref[v][x1 - 1][y2] - pref[v][x2][y1 - 1] + pref[v][x1 - 1][y1 - 1];
                    if (cnt > 0) distinct++;
                }
                sb.append(distinct).append('\n');
            }
        }
        System.out.print(sb.toString());
    }

    // Fast scanner using buffered byte array (handles EOF gracefully)
    private static class FastScanner {
        private final InputStream in = System.in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;

        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }

        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do {
                c = readByte();
                if (c == -1) return Integer.MIN_VALUE; // EOF
            } while (c <= ' ');
            if (c == '-') {
                sign = -1;
                c = readByte();
            }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

